import { LineChart } from '@mui/x-charts';
export default function Crypto() {
  return (
    <LineChart
      width={900}
      height={450}
      xAxis={[
        {
          data: [
            'Jul', 'Oct', '2024', 'Apr',
            'Jul', 'Oct', '2025', 'Apr'
          ],
          scaleType: 'band',
        },
      ]}
      series={[
        {
          label: 'v6',
          data: [0, 30, 80, 60, 55, 50, 45, 48],
          area: true,
        },
        {
          label: 'v7',
          data: [0, 0, 100, 180, 230, 300, 280, 310],
          area: true,
        },
        {
          label: 'v8',
          data: [0, 0, 0, 0, 0, 350, 410, 380],
          area: true,
        },
      ]}
    />
  );
}
